          <span className="font-mono">{t1 - t0}ms</span>
        </p>

        <div className="mt-6 flex gap-2 text-sm">
          <a
            className="rounded-xl border border-slate-800 bg-slate-950/30 px-4 py-2 text-slate-200 hover:border-slate-600"
