import { NextResponse } from "next/server";
import { getConfig } from "@/lib/store";
import { stableUniform01 } from "@/lib/random";
import { getRuntime } from "@/lib/runtime";
import { recordRequest, snapshotTenant } from "@/lib/telemetry";

function sleep(ms: number) {
  return new Promise<void>((resolve) => setTimeout(resolve, ms));
}

export async function GET(req: Request) {
  const started = Date.now();
  const config = await getConfig();

  const tenantId = req.headers.get("x-tenant-id");
  const requestId = req.headers.get("x-request-id") ?? crypto.randomUUID();
  const url = new URL(req.url);
  const units = Math.max(1, Math.min(100, Number(url.searchParams.get("units") ?? "1")));

  if (!tenantId) {
    const latencyMs = Date.now() - started;
    recordRequest({
      tenantId: "unknown",
      dailyUnitBudget: 0,
      latencyMs,
      ok: false,
      rejectReason: "missing_tenant",
    });
    return NextResponse.json({ error: "missing_tenant" }, { status: 400 });
  }

  const tenant = config.tenants[tenantId];
  if (!tenant) {
    const latencyMs = Date.now() - started;
    recordRequest({
      tenantId,
      dailyUnitBudget: 0,
      latencyMs,
      ok: false,
      rejectReason: "tenant_not_found",
    });
    return NextResponse.json({ error: "tenant_not_found" }, { status: 404 });
  }

  const rt = getRuntime(config);
  const tenantRt = rt.tenant(tenant);

  // Rate limit first: cheap rejection.
  if (!tenantRt.rps.take(1)) {
    const latencyMs = Date.now() - started;
    recordRequest({
      tenantId,
      dailyUnitBudget: tenant.dailyUnitBudget,
      latencyMs,
      ok: false,
      rejectReason: "rate_limited",
    });
    return NextResponse.json({ error: "rate_limited" }, { status: 429, headers: { "Retry-After": "1" } });
  }

  // Budget check (simple in-memory accounting). For demo purposes, budget is charged only on success.
  const snap = snapshotTenant(tenantId);
  if (snap.budget.remainingUnits < units) {
    const latencyMs = Date.now() - started;
    recordRequest({
      tenantId,
      dailyUnitBudget: tenant.dailyUnitBudget,
      latencyMs,
      ok: false,
      rejectReason: "budget_exhausted",
    });
    return NextResponse.json({ error: "budget_exhausted" }, { status: 429 });
  }

  // Concurrency: shared mode uses global-only (noisy neighbor). Bulkhead uses both global + per-tenant.
  const acquiredGlobal = rt.global.tryAcquire();
  if (!acquiredGlobal) {
    const latencyMs = Date.now() - started;
    recordRequest({
      tenantId,
      dailyUnitBudget: tenant.dailyUnitBudget,
      latencyMs,
      ok: false,
      rejectReason: "concurrency_rejected",
    });
    return NextResponse.json({ error: "busy_global" }, { status: 503 });
  }

  const acquiredTenant = config.mode === "bulkhead" ? tenantRt.concurrency.tryAcquire() : true;
  if (!acquiredTenant) {
    rt.global.release();
    const latencyMs = Date.now() - started;
    recordRequest({
      tenantId,
      dailyUnitBudget: tenant.dailyUnitBudget,
      latencyMs,
      ok: false,
      rejectReason: "concurrency_rejected",
    });
    return NextResponse.json({ error: "busy_tenant" }, { status: 503 });
  }

  let status = 200;
  let ok = true;
  let simulatedLatencyMs = 0;

  try {
    const u = (tag: string) => stableUniform01(`${tenantId}:${requestId}:${tag}`);
    const isError = u("err") < tenant.behavior.errorRate;
    const isTail = u("tail") < tenant.behavior.tailPct;
    const jitter = Math.floor(u("j") * tenant.behavior.jitterMs);
    const tail = isTail ? Math.floor(u("t") * tenant.behavior.tailLatencyMs) : 0;
    simulatedLatencyMs = tenant.behavior.baseLatencyMs + jitter + tail + Math.floor(units * 2);

    await sleep(simulatedLatencyMs);
    if (isError) {
      status = tenant.behavior.errorStatus;
      ok = false;
    }
  } catch {
    status = 500;
    ok = false;
  } finally {
    if (config.mode === "bulkhead") tenantRt.concurrency.release();
    rt.global.release();
  }

  const latencyMs = Date.now() - started;
  recordRequest({
    tenantId,
    dailyUnitBudget: tenant.dailyUnitBudget,
    latencyMs,
    ok: ok && status < 400,
    unitsCharged: ok ? units : 0,
  });

  return NextResponse.json(
    {
      tenantId,
      requestId,
      ok,
      status,
      mode: config.mode,
      units,
      latencyMs,
      simulatedLatencyMs,
      ts: new Date().toISOString(),
    },
    { status, headers: { "Cache-Control": "no-store" } },
  );
}

import * as fs from "fs";
import * as path from "path";

type Mode = "shared" | "bulkhead";

type Report = {
  now: string;
  config: { mode: Mode };
  tenants: Record<
    string,
    {
      total: number;
      errorRate: number;
      latencyMs: { p95: number };
      rejected: Record<string, number>;
      budget: { remainingUnits: number };
    }
  >;
};

function arg(name: string, def?: string) {
  const idx = process.argv.indexOf(`--${name}`);
  if (idx === -1) return def;
  return process.argv[idx + 1] ?? def;
}

async function json<T>(url: string, init?: RequestInit): Promise<T> {
  const res = await fetch(url, {
    ...init,
    headers: { "Content-Type": "application/json", ...(init?.headers || {}) },
    cache: "no-store",
  });
  const text = await res.text();
  if (!res.ok) throw new Error(`${res.status} ${res.statusText}: ${text}`);
  return JSON.parse(text) as T;
}

async function worker(params: { baseUrl: string; stopAt: number; tenantId: string; units: number }) {
  const { baseUrl, stopAt, tenantId, units } = params;
  while (Date.now() < stopAt) {
    try {
      await fetch(`${baseUrl}/api/work?units=${units}`, {
        headers: { "x-tenant-id": tenantId, "x-request-id": crypto.randomUUID() },
        cache: "no-store",
      });
    } catch {
      // ignore
    }
  }
}

async function main() {
  const baseUrl = arg("baseUrl", "http://localhost:3000")!;
  const mode = (arg("mode", "shared") as Mode) ?? "shared";

  const enterprise = "tenant-enterprise";
  const free = "tenant-free";

  await json(`${baseUrl}/api/reset`, { method: "POST" });
  await json(`${baseUrl}/api/config`, {
    method: "POST",
    body: JSON.stringify({ mode, globalMaxConcurrent: 60 }),
  });

  // Phase A: normal traffic (both tenants stable)
  const phaseAStop = Date.now() + 12_000;
  await Promise.all([
    worker({ baseUrl, stopAt: phaseAStop, tenantId: enterprise, units: 1 }),
    worker({ baseUrl, stopAt: phaseAStop, tenantId: free, units: 1 }),
  ]);
  const repA = await json<Report>(`${baseUrl}/api/report`);

  // Phase B: noisy neighbor (free tenant spikes and consumes shared capacity)
  const phaseBStop = Date.now() + 15_000;
  await Promise.all([
    ...Array.from({ length: 8 }, () =>
      worker({ baseUrl, stopAt: phaseBStop, tenantId: free, units: 2 }),
    ),
    worker({ baseUrl, stopAt: phaseBStop, tenantId: enterprise, units: 1 }),
  ]);
  const repB = await json<Report>(`${baseUrl}/api/report`);

  const artifact = {
    createdAt: new Date().toISOString(),
    mode,
    phases: {
      normal: summarize(repA),
      noisyNeighbor: summarize(repB),
    },
    interpretation:
      mode === "shared"
        ? "Shared pool: the spiky tenant can increase contention and degrade other tenants (p95 and rejects)."
        : "Bulkheads: per-tenant concurrency reserves capacity so the enterprise tenant stays more stable.",
  };

  const runsDir = path.join(process.cwd(), "runs");
  fs.mkdirSync(runsDir, { recursive: true });
  const outPath = path.join(runsDir, `tenant-lab-${mode}-${Date.now()}.json`);
  fs.writeFileSync(outPath, JSON.stringify(artifact, null, 2) + "\n", "utf-8");
  console.log(JSON.stringify({ outPath, artifact }, null, 2));
}

function summarize(rep: Report) {
  const out: any = {};
  for (const [tid, r] of Object.entries(rep.tenants)) {
    out[tid] = {
      total: r.total,
      errorRate: r.errorRate,
      p95: r.latencyMs.p95,
      rejected: r.rejected,
      remainingUnits: r.budget.remainingUnits,
    };
  }
  return out;
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});

