export class Semaphore {
  private readonly max: number;
  private inUse = 0;

  constructor(max: number) {
    this.max = Math.max(1, Math.floor(max));
  }

  tryAcquire() {
    if (this.inUse >= this.max) return false;
    this.inUse += 1;
    return true;
  }

  release() {
    this.inUse = Math.max(0, this.inUse - 1);
  }

  snapshot() {
    return { inUse: this.inUse, max: this.max };
  }
}

export class TokenBucket {
  private readonly capacity: number;
  private readonly refillPerSec: number;
  private tokens: number;
  private lastRefillMs: number;

  constructor(params: { capacity: number; refillPerSec: number }) {
    this.capacity = Math.max(1, params.capacity);
    this.refillPerSec = Math.max(0, params.refillPerSec);
    this.tokens = this.capacity;
    this.lastRefillMs = Date.now();
  }

  take(cost = 1) {
    this.refill();
    if (this.tokens >= cost) {
      this.tokens -= cost;
      return true;
    }
    return false;
  }

  private refill() {
    const now = Date.now();
    const elapsedSec = (now - this.lastRefillMs) / 1000;
    if (elapsedSec <= 0) return;
    const add = elapsedSec * this.refillPerSec;
    this.tokens = Math.min(this.capacity, this.tokens + add);
    this.lastRefillMs = now;
  }
}

import { createHash } from "crypto";

export function stableUniform01(seed: string) {
  const digest = createHash("sha256").update(seed).digest();
  const bucket = digest.readUInt32BE(0);
  return bucket / 0xffffffff;
}

import { Semaphore, TokenBucket } from "@/lib/limiters";
