import { createHash, randomUUID } from "node:crypto";
import { z } from "zod";

export const LedgerEventSchema = z.object({
  id: z.string(),
  ts: z.string(),
  type: z.enum(["job_started", "dataset_written", "lineage_edge", "job_completed"]),
  actor: z.string().default("pipeline"),
  jobRunId: z.string(),
  payload: z.record(z.unknown()),
  prevHash: z.string().nullable(),
  hash: z.string(),
});

export type LedgerEvent = z.infer<typeof LedgerEventSchema>;

function stableStringify(obj: unknown): string {
  // Good enough for demo. In prod: canonical JSON or protobuf with deterministic ordering.
  return JSON.stringify(obj, Object.keys(obj as any).sort());
}

function hashEvent(params: { prevHash: string | null; body: Omit<LedgerEvent, "hash"> }): string {
  const h = createHash("sha256");
  h.update(params.prevHash ?? "GENESIS");
  h.update("|");
  h.update(stableStringify(params.body));
  return h.digest("hex");
}

export class Ledger {
  private events: LedgerEvent[] = [];

  append(params: {
    type: LedgerEvent["type"];
    actor?: string;
    jobRunId: string;
    payload: Record<string, unknown>;
  }): LedgerEvent {
    const prevHash = this.events.length ? this.events[this.events.length - 1].hash : null;
    const body: Omit<LedgerEvent, "hash"> = {
      id: randomUUID(),
      ts: new Date().toISOString(),
      type: params.type,
      actor: params.actor ?? "pipeline",
      jobRunId: params.jobRunId,
      payload: params.payload,
      prevHash,
    };
    const hash = hashEvent({ prevHash, body });
    const event: LedgerEvent = { ...body, hash };
    this.events.push(event);
    return event;
  }

  list(limit = 200): LedgerEvent[] {
    return this.events.slice(-limit);
  }

  headHash(): string | null {
    return this.events.length ? this.events[this.events.length - 1].hash : null;
  }

  verify(): { ok: boolean; checked: number; badIndex?: number; expected?: string; actual?: string } {
    let prevHash: string | null = null;
    for (let i = 0; i < this.events.length; i++) {
      const e = this.events[i];
      const { hash, ...body } = e;
      const expected = hashEvent({ prevHash, body });
      if (expected !== hash) {
        return { ok: false, checked: i + 1, badIndex: i, expected, actual: hash };
      }
      prevHash = hash;
    }
    return { ok: true, checked: this.events.length };
  }
}

import { randomUUID } from "node:crypto";

export type LineageNode = {
  id: string;
  kind: "dataset";
  name: string;
  version: string;
};

export type LineageEdge = {
  id: string;
  from: string;
  to: string;
  type: "derived_from";
  ts: string;
  jobRunId: string;
};

export class LineageGraph {
  private nodes = new Map<string, LineageNode>();
  private edges: LineageEdge[] = [];

  upsertDataset(params: { name: string; version: string }): LineageNode {
    const key = `${params.name}@${params.version}`;
    const existing = this.nodes.get(key);
    if (existing) return existing;
    const node: LineageNode = { id: randomUUID(), kind: "dataset", name: params.name, version: params.version };
    this.nodes.set(key, node);
    return node;
  }

  addDerivedFrom(params: { from: LineageNode; to: LineageNode; jobRunId: string }): LineageEdge {
    const edge: LineageEdge = {
      id: randomUUID(),
      from: params.from.id,
      to: params.to.id,
      type: "derived_from",
      ts: new Date().toISOString(),
      jobRunId: params.jobRunId,
    };
    this.edges.push(edge);
    return edge;
  }

  snapshot() {
    return {
      nodes: [...this.nodes.values()].sort((a, b) => a.name.localeCompare(b.name)),
      edges: [...this.edges].slice(-300),
    };
  }
}

import { randomUUID } from "node:crypto";
import { z } from "zod";
import type { Ledger } from "./ledger";
import type { LineageGraph } from "./lineage";

const RawPostSchema = z.object({
  id: z.string(),
  authorId: z.string(),
  title: z.string(),
  body: z.string(),
  createdAt: z.string(),
});

type RawPost = z.infer<typeof RawPostSchema>;

type SanitizedPost = RawPost & {
  body: string;
  piiRedacted: boolean;
};

type Aggregated = {
  byAuthor: Array<{ authorId: string; posts: number }>;
  totalPosts: number;
};

function sampleRaw(): RawPost[] {
  return [
    {
      id: "p1",
      authorId: "u1",
      title: "Hello",
      body: "Contact me at alice@example.com",
      createdAt: new Date(Date.now() - 60_000).toISOString(),
    },
    {
      id: "p2",
      authorId: "u2",
      title: "Design notes",
      body: "Call 555-0100 for follow-ups",
      createdAt: new Date(Date.now() - 30_000).toISOString(),
    },
    {
      id: "p3",
      authorId: "u1",
      title: "More",
      body: "No PII here",
      createdAt: new Date().toISOString(),
    },
  ].map((p) => RawPostSchema.parse(p));
}

function redactPII(text: string): { text: string; redacted: boolean } {
  const emailRe = /[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi;
  const phoneRe = /\b\d{3}-\d{4}\b/g;
  const before = text;
  const after = before.replace(emailRe, "[REDACTED_EMAIL]").replace(phoneRe, "[REDACTED_PHONE]");
  return { text: after, redacted: after !== before };
}

function sanitize(raw: RawPost[]): SanitizedPost[] {
  return raw.map((p) => {
    const r = redactPII(p.body);
    return { ...p, body: r.text, piiRedacted: r.redacted };
  });
}

function aggregate(posts: SanitizedPost[]): Aggregated {
  const counts = new Map<string, number>();
  for (const p of posts) counts.set(p.authorId, (counts.get(p.authorId) ?? 0) + 1);
  return {
    byAuthor: [...counts.entries()]
      .map(([authorId, posts]) => ({ authorId, posts }))
      .sort((a, b) => b.posts - a.posts),
    totalPosts: posts.length,
  };
}

export type PipelineRunResult = {
  jobRunId: string;
  datasets: {
    raw: { name: string; version: string; rows: number };
    sanitized: { name: string; version: string; rows: number };
    aggregated: { name: string; version: string; rows: number };
  };
};

export function runPipeline(params: {
  jobName: string;
  ledger: Ledger;
  lineage: LineageGraph;
}): PipelineRunResult {
  const jobRunId = `${params.jobName}-${randomUUID()}`;
  params.ledger.append({ type: "job_started", jobRunId, payload: { jobName: params.jobName } });

  const rawV = new Date().toISOString().slice(0, 10);
  const sanitizedV = `${rawV}-san`;
  const aggV = `${rawV}-agg`;

  const raw = sampleRaw();
  const rawNode = params.lineage.upsertDataset({ name: "posts_raw", version: rawV });
  params.ledger.append({
    type: "dataset_written",
    jobRunId,
    payload: { dataset: rawNode.name, version: rawNode.version, rows: raw.length },
  });

  const sanitized = sanitize(raw);
  const sanNode = params.lineage.upsertDataset({ name: "posts_sanitized", version: sanitizedV });
  params.lineage.addDerivedFrom({ from: rawNode, to: sanNode, jobRunId });
  params.ledger.append({
    type: "lineage_edge",
    jobRunId,
    payload: { from: `${rawNode.name}@${rawNode.version}`, to: `${sanNode.name}@${sanNode.version}` },
  });
  params.ledger.append({
    type: "dataset_written",
    jobRunId,
    payload: {
      dataset: sanNode.name,
      version: sanNode.version,
      rows: sanitized.length,
      piiRedacted: sanitized.filter((p) => p.piiRedacted).length,
    },
  });

  const agg = aggregate(sanitized);
  const aggNode = params.lineage.upsertDataset({ name: "posts_agg", version: aggV });
  params.lineage.addDerivedFrom({ from: sanNode, to: aggNode, jobRunId });
  params.ledger.append({
    type: "lineage_edge",
    jobRunId,
    payload: { from: `${sanNode.name}@${sanNode.version}`, to: `${aggNode.name}@${aggNode.version}` },
  });
  params.ledger.append({
    type: "dataset_written",
    jobRunId,
    payload: { dataset: aggNode.name, version: aggNode.version, rows: agg.byAuthor.length },
  });

  params.ledger.append({ type: "job_completed", jobRunId, payload: { ok: true } });

  return {
    jobRunId,
    datasets: {
      raw: { name: rawNode.name, version: rawNode.version, rows: raw.length },
      sanitized: { name: sanNode.name, version: sanNode.version, rows: sanitized.length },
      aggregated: { name: aggNode.name, version: aggNode.version, rows: agg.byAuthor.length },
    },
  };
}

