    ts: new Date().toISOString(),
    level: params.level,
    msg: params.msg,
    traceId: params.traceId,
    requestId: params.requestId,
    fields: params.fields ? redact(params.fields) : undefined,
  };
  console.log(JSON.stringify(entry));
}

