let reserved = false;
let charged = false;

const result = await runSaga([
  {
    name: "reserve_inventory",
    run: async () => {
      reserved = true;
      console.log("reserved");
    },
    compensate: async () => {
      reserved = false;
      console.log("unreserved");
    },
  },
  {
    name: "charge_payment",
    run: async () => {
      charged = true;
      console.log("charged");
      throw new Error("payment processor timeout");
    },
    compensate: async () => {
      charged = false;
      console.log("refunded");
    },
  },
]);

console.log({ result, reserved, charged });
if (!result.ok) process.exit(1);

export type Step = {
  name: string;
  run: () => Promise<void>;
  compensate: () => Promise<void>;
};

export async function runSaga(steps: Step[]) {
  const completed: Step[] = [];
  try {
    for (const s of steps) {
      await s.run();
      completed.push(s);
    }
    return { ok: true };
  } catch (e) {
    for (const s of completed.reverse()) {
      try {
        await s.compensate();
      } catch {
        // best-effort; real systems record compensation failures.
      }
    }
    return { ok: false, error: e instanceof Error ? e.message : String(e) };
  }
}

