import { z } from "zod";

const ArgsSchema = z.object({ baseUrl: z.string().url() });

function parseArgs(argv: string[]) {
  const out: Record<string, string> = {};
  for (let i = 0; i < argv.length; i++) {
    const token = argv[i];
    if (!token.startsWith("--")) continue;
    const key = token.slice(2);
    const value = argv[i + 1] && !argv[i + 1].startsWith("--") ? argv[++i] : "true";
    out[key] = value;
  }
  return ArgsSchema.parse(out);
}

async function json<T>(url: string, init?: RequestInit): Promise<T> {
  const res = await fetch(url, { ...init, headers: { "Content-Type": "application/json", ...(init?.headers || {}) } });
  if (!res.ok) throw new Error(`${res.status} ${res.statusText} for ${url}`);
  return (await res.json()) as T;
}

function assert(condition: unknown, msg: string): asserts condition {
  if (!condition) throw new Error(msg);
}

async function main() {
  const args = parseArgs(process.argv.slice(2));
  const base = args.baseUrl.replace(/\/$/, "");
  await json(`${base}/api/reset`, { method: "POST", body: "{}" });

  // invalidation strategy
  await json(`${base}/api/config`, { method: "POST", body: JSON.stringify({ strategy: "invalidation", ttlMs: 5000 }) });
  await json(`${base}/api/item?id=item-1`);
  const w1 = await json<any>(`${base}/api/item`, { method: "PUT", body: JSON.stringify({ id: "item-1", value: "v2" }) });
  const r1 = await json<any>(`${base}/api/item?id=item-1`);
  assert(r1.record.version === w1.record.version, "read-after-write should see latest");

  // versioned keys strategy
  await json(`${base}/api/config`, { method: "POST", body: JSON.stringify({ strategy: "versioned", ttlMs: 5000 }) });
  const w2 = await json<any>(`${base}/api/item`, { method: "PUT", body: JSON.stringify({ id: "item-1", value: "v3" }) });
  const r2 = await json<any>(`${base}/api/item?id=item-1`);
  assert(r2.record.version === w2.record.version, "versioned key read should see latest");

  console.log(JSON.stringify({ ok: true }, null, 2));
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});

