const inflight = new Map<string, Promise<number>>();

async function singleflight(key: string, fn: () => Promise<number>) {
  const existing = inflight.get(key);
  if (existing) return existing;
  const p = fn().finally(() => inflight.delete(key));
  inflight.set(key, p);
  return p;
}

