  for (const tab of tabs) {
    const crashed = tab === "A" && t >= 10_000;
    if (crashed) continue;
    lease = tryAcquire(lease, tab, t, ttl);
    if (lease && lease.leader === tab) lease = renew(lease, tab, t, ttl);
  }
  log.push({ t, lease });
}

