function merge(prev: Msg[], incoming: Msg[]) {
  const byCursor = new Map(prev.map((m) => [m.cursor, m]));
  for (const m of incoming) byCursor.set(m.cursor, m);
  return [...byCursor.values()].sort((a, b) => b.cursor - a.cursor);
