type Clock = Record<string, number>;

function bump(clock: Clock, node: string): Clock {
  return { ...clock, [node]: (clock[node] ?? 0) + 1 };
}

function merge(a: Clock, b: Clock): Clock {
  const out: Clock = { ...a };
  for (const [k, v] of Object.entries(b)) out[k] = Math.max(out[k] ?? 0, v);
  return out;
}

function compare(a: Clock, b: Clock): "before" | "after" | "concurrent" | "equal" {
  const keys = new Set([...Object.keys(a), ...Object.keys(b)]);
  let aLeq = true;
  let bLeq = true;
  let anyDiff = false;
  for (const k of keys) {
    const av = a[k] ?? 0;
    const bv = b[k] ?? 0;
    if (av !== bv) anyDiff = true;
    if (av > bv) aLeq = false;
    if (bv > av) bLeq = false;
  }
  if (!anyDiff) return "equal";
  if (aLeq && !bLeq) return "before";
  if (bLeq && !aLeq) return "after";
  return "concurrent";
}

// Simulate concurrent updates on two nodes.
let a: Clock = {};
let b: Clock = {};

a = bump(a, "A"); // A writes
b = bump(b, "B"); // B writes concurrently

const relation = compare(a, b);
const merged = merge(a, b);

console.log(JSON.stringify({ a, b, relation, merged }, null, 2));

