  if (params.legalHoldUsers.has(params.record.userId)) return { delete: false, reason: "legal_hold" };
  if (ageDays >= params.policy.deleteAfterDays) return { delete: true, reason: "ttl" };
  return { delete: false, reason: "keep" };
}

