class FencedWriter {
  private currentToken = 0;
  private value = "";

  electNewLeader() {
    this.currentToken++;
    return this.currentToken;
  }

  write(token: number, v: string) {
    if (token !== this.currentToken) throw new Error("stale_fencing_token");
    this.value = v;
  }

  read() {
    return this.value;
  }
}

